(window.webpackJsonp=window.webpackJsonp||[]).push([[64],{691:function(r,n){r.exports='\x3c!-- \r\ntitle: 10-Linux基础\r\nsort: \r\n--\x3e \r\n# Linux 基础\r\n\r\n## 文件和目录\r\n\r\n- /bin\t二进制文件\r\n- /home 用户目录\r\n\r\n\r\n\r\n## 创建文件\r\n\r\n- mkdir -p 递归创建文件夹(parents)\r\n- touch 创建文件\r\n- gedit 打开文件编辑   \r\n- funny\r\n\r\n  > mkdir a/b/c/d/e/f a/b/c/d/f  a/b/c/e a/b/d a/c b\r\n\r\n\r\n\r\n## 删除文件\r\n\r\n- rm 删除命令\r\n  > -i\t确认删除\r\n  >\r\n  > -f\t无需确认(force)\r\n  >\r\n  > -r\t删除文件夹\r\n  \r\n  \r\n\r\n## 拷贝文件\r\n\r\n- cp -> copy\r\n\r\n  复制文件\r\n\r\n  > -i\t交互模式删除\r\n  >\r\n  > -f\t强制覆盖\r\n  >\r\n  > -v\t显示过程(verbose)\r\n  >\r\n  > -r\t拷贝目录(recursive)\r\n  >\r\n  > -a\t拷贝原有属性(attric)\r\n\r\n\r\n\r\n## 移动文件\r\n\r\n+ mv\r\n\r\n  移动文件 \r\n\r\n  > -ifv\t同上\r\n  >\r\n  > -r\t\t 不需要\r\n\r\n\r\n\r\n## 其他命令\r\n\r\n1. ### Tab键\r\n\r\n2. ### Which\r\n\r\n3. ### Ctrl+C\r\n\r\n4. ### cal\r\n\r\n   > -3\t显示三个月\r\n   >\r\n   > -y\t显示一年\r\n   >\r\n   > -j\t一年中第xx天\r\n   >\r\n   > 1997\t显示1997年日历\r\n\r\n5. ### date\r\n\r\n   > "+%Y-%m-%d %H:%M:%S "\r\n   >\r\n   > %F\t日期\r\n   >\r\n   > %T\t时间\r\n\r\n6. ### history \r\n\r\n   ！序号\t执行该命令  \r\n\r\n7. ### cat \r\n\r\n   > -n\t编号(number)\r\n   >\r\n   > -b\t编号（非空行）\r\n   >\r\n   > -s\t多空行只显示一行\r\n\r\n8. ### more\r\n\r\n   windows中也有\r\n\r\n   > +数字\t从该行开始显示\r\n   >\r\n   > -p\t\t\t先清屏再显示\r\n\r\n   ### 快捷键\r\n\r\n   > 空格\t下一屏\r\n   >\r\n   > 回车\t下一行\r\n   >\r\n   > f/b\t\t上一页/下一页\r\n\r\n   \r\n'}}]);